diff --git a/tests/d3d12_resource.c b/tests/d3d12_resource.c
index d963d851..74f327f1 100644
--- a/tests/d3d12_resource.c
+++ b/tests/d3d12_resource.c
@@ -6267,3 +6267,83 @@ void test_buffer_rtv_dsv_usage(void)

     destroy_test_context(&context);
 }
+
+void test_resource_retain_workaround(void)
+{
+    struct test_context_desc context_desc;
+    ID3D12Resource *late_idle_outputs;
+    struct test_context context;
+    struct resource_readback rb;
+    ID3D12Resource *outputs[2];
+    ID3D12Resource *inputs[64];
+    float input_data[4096];
+    unsigned int i;
+
+    /* Test bench to demonstrate that the use-after-free workarounds work as intended.
+     * It should pass without VVL complaining about use-after-free errors. */
+
+    memset(&context_desc, 0, sizeof(context_desc));
+    context_desc.no_pipeline = true;
+    context_desc.no_render_target = true;
+    context_desc.no_root_signature = true;
+
+    vkd3d_set_out_of_spec_test_behavior(VKD3D_DEBUG_CONTROL_OUT_OF_SPEC_BEHAVIOR_RESOURCE_USE_AFTER_FREE, TRUE);
+    if (!init_test_context(&context, &context_desc))
+        return;
+
+    for (i = 0; i < ARRAY_SIZE(input_data); i++)
+        input_data[i] = (float)i + 1.0f;
+
+    /* For internal testing purposes, check that allocating and releasing a resource right away does not hit retain path. */
+    outputs[0] = create_default_buffer(context.device, sizeof(input_data), D3D12_RESOURCE_FLAG_NONE, D3D12_RESOURCE_STATE_COMMON);
+    ID3D12Resource_Release(outputs[0]);
+    /* Try again, but with non-suballocated buffers. */
+    outputs[0] = create_default_buffer(context.device, 4 * 1024 * 1024, D3D12_RESOURCE_FLAG_NONE, D3D12_RESOURCE_STATE_COMMON);
+    ID3D12Resource_Release(outputs[0]);
+
+    /* These will be suballocated. */
+    for (i = 0; i < ARRAY_SIZE(inputs); i++)
+        inputs[i] = create_upload_buffer(context.device, sizeof(input_data), input_data);
+
+    /* Make sure we hit dedicated allocation path. */
+    for (i = 0; i < ARRAY_SIZE(outputs); i++)
+        outputs[i] = create_default_buffer(context.device, 4 * 1024 * 1024, D3D12_RESOURCE_FLAG_NONE, D3D12_RESOURCE_STATE_COMMON);
+
+    for (i = 0; i < ARRAY_SIZE(inputs); i++)
+    {
+        ID3D12GraphicsCommandList_CopyBufferRegion(context.list, outputs[0], i * sizeof(input_data), inputs[i], 0, sizeof(input_data));
+        ID3D12GraphicsCommandList_CopyBufferRegion(context.list, outputs[1], i * sizeof(input_data), inputs[i], 0, sizeof(input_data));
+    }
+
+    late_idle_outputs = create_default_buffer(context.device, 1 * 1024 * 1024, D3D12_RESOURCE_FLAG_NONE, D3D12_RESOURCE_STATE_COMMON);
+
+    ID3D12GraphicsCommandList_Close(context.list);
+    /* This flushes memory clears. */
+    exec_command_list(context.queue, context.list);
+    /* This should be retained due to clear being in-flight. */
+    ID3D12Resource_Release(late_idle_outputs);
+
+    /* Deep UB. Use-after-free. This can trigger DEVICE_LOST on Windows AMD at least,
+     * so there is evidence of drivers not doing these hacks by default at least ... */
+    ID3D12Resource_Release(outputs[1]);
+    for (i = 0; i < ARRAY_SIZE(inputs); i++)
+        ID3D12Resource_Release(inputs[i]);
+
+    ID3D12GraphicsCommandList_Reset(context.list, context.allocator, NULL);
+    transition_resource_state(context.list, outputs[0],
+            D3D12_RESOURCE_STATE_COPY_DEST, D3D12_RESOURCE_STATE_COPY_SOURCE);
+    get_buffer_readback_with_command_list(outputs[0], DXGI_FORMAT_UNKNOWN, &rb, context.queue, context.list);
+
+    for (i = 0; i < ARRAY_SIZE(input_data) * ARRAY_SIZE(inputs); i++)
+    {
+        float value, expected;
+        value = get_readback_float(&rb, i, 0);
+        expected = (float)(i % ARRAY_SIZE(input_data)) + 1.0f;
+        ok(value == expected, "value %u, expected %f, got %f.\n", i, expected, value);
+    }
+
+    release_resource_readback(&rb);
+    ID3D12Resource_Release(outputs[0]);
+    destroy_test_context(&context);
+    vkd3d_set_out_of_spec_test_behavior(VKD3D_DEBUG_CONTROL_OUT_OF_SPEC_BEHAVIOR_RESOURCE_USE_AFTER_FREE, FALSE);
+}
diff --git a/tests/d3d12_tests.h b/tests/d3d12_tests.h
index 99bdb869..c776aeab 100644
--- a/tests/d3d12_tests.h
+++ b/tests/d3d12_tests.h
@@ -569,3 +569,4 @@ decl_test(test_copy_queue_depth_stencil_msaa);
 decl_test(test_sample_shading_coverage_mask);
 decl_test(test_render_target_support_validation);
 decl_test(test_descriptor_heap_broken_table_va);
+decl_test(test_resource_retain_workaround);

commit 42d6787c8d2be096951017664d9a5eebe8224b73
Author: Hans-Kristian Arntzen <post@arntzen-software.no>
Date:   Fri May 29 15:40:14 2026 +0200

    vkd3d: If GPU clears are in flight, retain the resource to avoid stall.

    Somewhat speculative, but if we can avoid stalls on client threads,
    and the scaffolding is already in place, why not.

    Signed-off-by: Hans-Kristian Arntzen <post@arntzen-software.no>
---
 libs/vkd3d/memory.c        | 16 ++++++++++++++++
 libs/vkd3d/resource.c      | 18 ++++++++++++++++--
 libs/vkd3d/vkd3d_private.h |  2 ++
 3 files changed, 34 insertions(+), 2 deletions(-)

diff --git a/libs/vkd3d/memory.c b/libs/vkd3d/memory.c
index ad2bcdd4..2ff9904f 100644
--- a/libs/vkd3d/memory.c
+++ b/libs/vkd3d/memory.c
@@ -603,6 +603,22 @@ bool vkd3d_memory_transfer_queue_poll_allocation_idle(struct vkd3d_memory_transf
     return ret;
 }

+bool vkd3d_memory_transfer_queue_clear_in_flight(struct vkd3d_memory_transfer_queue *queue,
+        const struct vkd3d_memory_allocation *allocation)
+{
+    bool ret;
+    assert(allocation->clear_semaphore_value);
+    pthread_mutex_lock(&queue->mutex);
+    /* We might be able to prove that the resource is in use by our internal clear queue.
+     * In this case, it would be a stall to free the resource, which is unfortunate.
+     * We can use this as a hint to ask the resource to be released in a deferred way. */
+    ret = allocation->clear_semaphore_value < queue->next_signal_value;
+    pthread_mutex_unlock(&queue->mutex);
+    if (ret)
+        ret = !vkd3d_memory_transfer_queue_wait_semaphore(queue, allocation->clear_semaphore_value, 0);
+    return ret;
+}
+
 static void vkd3d_memory_transfer_queue_wait_allocation(struct vkd3d_memory_transfer_queue *queue,
         const struct vkd3d_memory_allocation *allocation)
 {
diff --git a/libs/vkd3d/resource.c b/libs/vkd3d/resource.c
index 5c56d74a..44c28fc1 100644
--- a/libs/vkd3d/resource.c
+++ b/libs/vkd3d/resource.c
@@ -2338,6 +2338,19 @@ static bool d3d12_resource_is_gpu_idle(struct d3d12_resource *resource)
     }
 }

+static bool d3d12_resource_is_gpu_clear_pending(struct d3d12_resource *resource)
+{
+    if ((resource->flags & VKD3D_RESOURCE_ALLOCATION) && resource->mem.device_allocation.vk_memory &&
+       resource->mem.clear_semaphore_value)
+    {
+        return vkd3d_memory_transfer_queue_clear_in_flight(&resource->device->memory_transfers, &resource->mem);
+    }
+    else
+    {
+        return false;
+    }
+}
+
 static ULONG STDMETHODCALLTYPE d3d12_resource_Release(d3d12_resource_iface *iface)
 {
     struct d3d12_resource *resource = impl_from_ID3D12Resource2(iface);
@@ -2358,10 +2371,11 @@ static ULONG STDMETHODCALLTYPE d3d12_resource_Release(d3d12_resource_iface *ifac
         /* If we can trivially prove the resource has never been used on GPU,
          * ignore this. This is mostly relevant for clear queue.
          * We don't want to defer the release, only to have to eat an extra wait on the clear queue.
-         * TODO: Potential improvement is to use deferred release for resources which have yet to be cleared
-         * to avoid the stall on client thread. */
+         * If we know GPU clears are in flight, retain as a performance optimization. */
         if (d3d12_resource_is_gpu_idle(resource))
             retain = false;
+        else if (d3d12_resource_is_gpu_clear_pending(resource))
+            retain = true;

         if (retain)
         {
diff --git a/libs/vkd3d/vkd3d_private.h b/libs/vkd3d/vkd3d_private.h
index 1ef897ff..ed449a1f 100644
--- a/libs/vkd3d/vkd3d_private.h
+++ b/libs/vkd3d/vkd3d_private.h
@@ -968,6 +968,8 @@ HRESULT vkd3d_memory_transfer_queue_write_subresource(struct vkd3d_memory_transf
 HRESULT vkd3d_memory_transfer_queue_build_empty_rtas(struct vkd3d_memory_transfer_queue *queue);
 bool vkd3d_memory_transfer_queue_poll_allocation_idle(struct vkd3d_memory_transfer_queue *queue,
         const struct vkd3d_memory_allocation *allocation);
+bool vkd3d_memory_transfer_queue_clear_in_flight(struct vkd3d_memory_transfer_queue *queue,
+        const struct vkd3d_memory_allocation *allocation);

 struct vkd3d_memory_allocator
