commit 1ae876007a78a309ac34d549798699d037188836
Author: Hans-Kristian Arntzen <post@arntzen-software.no>
Date:   Fri May 29 15:32:26 2026 +0200

    vkd3d: Don't deferred release resources which are provably idle.

    If we can prove a clear queue resource never started executing,
    there is no point in deferring the release, since there is no way that
    resource could be part of a submission. Use-before-alloc holes exist,
    but that case is completely broken anyway and is not something we can
    workaround in any meaningful way.

    Signed-off-by: Hans-Kristian Arntzen <post@arntzen-software.no>
---
 libs/vkd3d/memory.c        | 15 +++++++++++++++
 libs/vkd3d/resource.c      | 22 ++++++++++++++++++++++
 libs/vkd3d/vkd3d_private.h |  2 ++
 3 files changed, 39 insertions(+)

diff --git a/libs/vkd3d/memory.c b/libs/vkd3d/memory.c
index e1d41d02..ad2bcdd4 100644
--- a/libs/vkd3d/memory.c
+++ b/libs/vkd3d/memory.c
@@ -588,6 +588,21 @@ HRESULT vkd3d_memory_transfer_queue_build_empty_rtas(struct vkd3d_memory_transfe
     return S_OK;
 }

+bool vkd3d_memory_transfer_queue_poll_allocation_idle(struct vkd3d_memory_transfer_queue *queue,
+        const struct vkd3d_memory_allocation *allocation)
+{
+    bool ret;
+    assert(allocation->clear_semaphore_value);
+    pthread_mutex_lock(&queue->mutex);
+    /* If we haven't performed any ExecuteCommandLists calls since resource was created,
+     * we can prove that the resource cannot possibly be used in a current submit.
+     * The only case where that could happen is a case of use-before-alloc scenarios which is a very theoretical hole,
+     * but our idea of doing clear submits breaks down in that world anyway. */
+    ret = allocation->clear_semaphore_value == queue->next_signal_value;
+    pthread_mutex_unlock(&queue->mutex);
+    return ret;
+}
+
 static void vkd3d_memory_transfer_queue_wait_allocation(struct vkd3d_memory_transfer_queue *queue,
         const struct vkd3d_memory_allocation *allocation)
 {
diff --git a/libs/vkd3d/resource.c b/libs/vkd3d/resource.c
index 96dc5b4f..5c56d74a 100644
--- a/libs/vkd3d/resource.c
+++ b/libs/vkd3d/resource.c
@@ -2324,6 +2324,20 @@ static void d3d12_device_add_queue_timeline_deferred_decref(struct d3d12_device
     }
 }

+static bool d3d12_resource_is_gpu_idle(struct d3d12_resource *resource)
+{
+    if ((resource->flags & VKD3D_RESOURCE_ALLOCATION) && resource->mem.device_allocation.vk_memory &&
+        resource->mem.clear_semaphore_value)
+    {
+        return vkd3d_memory_transfer_queue_poll_allocation_idle(&resource->device->memory_transfers, &resource->mem);
+    }
+    else
+    {
+        /* We cannot possibly know. */
+        return false;
+    }
+}
+
 static ULONG STDMETHODCALLTYPE d3d12_resource_Release(d3d12_resource_iface *iface)
 {
     struct d3d12_resource *resource = impl_from_ID3D12Resource2(iface);
@@ -2341,6 +2355,14 @@ static ULONG STDMETHODCALLTYPE d3d12_resource_Release(d3d12_resource_iface *ifac
         retain = (resource->flags & VKD3D_RESOURCE_RETAINED_GPU_REFERENCE) ||
                  VKD3D_CONFIG_FLAG_IS_SET(DEFER_RESOURCE_DESTRUCTION);

+        /* If we can trivially prove the resource has never been used on GPU,
+         * ignore this. This is mostly relevant for clear queue.
+         * We don't want to defer the release, only to have to eat an extra wait on the clear queue.
+         * TODO: Potential improvement is to use deferred release for resources which have yet to be cleared
+         * to avoid the stall on client thread. */
+        if (d3d12_resource_is_gpu_idle(resource))
+            retain = false;
+
         if (retain)
         {
             bool sparse = !!(resource->flags & VKD3D_RESOURCE_RESERVED);
diff --git a/libs/vkd3d/vkd3d_private.h b/libs/vkd3d/vkd3d_private.h
index adc0cc76..1ef897ff 100644
--- a/libs/vkd3d/vkd3d_private.h
+++ b/libs/vkd3d/vkd3d_private.h
@@ -966,6 +966,8 @@ HRESULT vkd3d_memory_transfer_queue_flush(struct vkd3d_memory_transfer_queue *qu
 HRESULT vkd3d_memory_transfer_queue_write_subresource(struct vkd3d_memory_transfer_queue *queue,
         struct d3d12_resource *resource, uint32_t subresource_idx, VkOffset3D offset, VkExtent3D extent);
 HRESULT vkd3d_memory_transfer_queue_build_empty_rtas(struct vkd3d_memory_transfer_queue *queue);
+bool vkd3d_memory_transfer_queue_poll_allocation_idle(struct vkd3d_memory_transfer_queue *queue,
+        const struct vkd3d_memory_allocation *allocation);

 struct vkd3d_memory_allocator
 {

commit 4a94bbdd2a524ff08d8b609664c0dfcfd2e95a75
Author: Hans-Kristian Arntzen <post@arntzen-software.no>
Date:   Thu May 28 17:10:39 2026 +0200

    vkd3d: Rethink how we retain resources.

    Remove the old path. There is a path for sparse where we hold onto it
    "indefinitely" which is somewhat safe since we're only consuming VA
    space, and this has been known to be a thing in AC: Valhalla.

    For non-sparse, we made the assumption that we could just release the
    resource right after QueueSubmit since page tables shouldn't have been
    able to update early, but that's not really true and we should do a
    better job.

    In the new path, we do the conservative "correct" thing and wait until
    all pending GPU work is done.

    Signed-off-by: Hans-Kristian Arntzen <post@arntzen-software.no>
---
 libs/vkd3d/command.c       |  97 ++++++++++++++++++------------------------
 libs/vkd3d/resource.c      | 103 +++++++++++++++++++++++++++++++++------------
 libs/vkd3d/vkd3d_private.h |  11 +++--
 3 files changed, 126 insertions(+), 85 deletions(-)

diff --git a/libs/vkd3d/command.c b/libs/vkd3d/command.c
index 83694b95..cb6d5e31 100644
--- a/libs/vkd3d/command.c
+++ b/libs/vkd3d/command.c
@@ -3230,56 +3230,6 @@ struct vkd3d_queue_family_info *d3d12_device_get_vkd3d_queue_family(struct d3d12
     }
 }

-/* This is used for workaround purposes for when some games screw up use-after-free of in-flight resources.
- * If resources are destroyed in-flight that's usually fine since GPU page tables are not updated
- * while a submission is in flight, but since we thread the actual submissions, we might observe behavior
- * that might not happen on Windows.
- * For workaround purposes, it's enough that we just defer the actual final decref until all dependent
- * vkQueueSubmit calls have gone through on CPU timeline.
- * This can be extended as needed to deal with GPU timeline too, but that's only relevant if truly needed,
