+            return VK_OPACITY_MICROMAP_FORMAT_2_STATE_KHR;
         case D3D12_RAYTRACING_OPACITY_MICROMAP_FORMAT_OC1_4_STATE:
-            return VK_OPACITY_MICROMAP_FORMAT_4_STATE_EXT;
+            return VK_OPACITY_MICROMAP_FORMAT_4_STATE_KHR;
