commit d1e166fba39585ca838b20082ece5e1f2714c69d
Author: Hans-Kristian Arntzen <post@arntzen-software.no>
Date:   Mon May 4 11:25:07 2026 +0200

    vkd3d: Use VK_KHR_maintenance11.

    Should resolve the ugly 2D -> 2DArray hackery.

    Signed-off-by: Hans-Kristian Arntzen <post@arntzen-software.no>
---
 libs/vkd3d/device.c        |  7 +++++++
 libs/vkd3d/resource.c      | 13 ++++++++++++-
 libs/vkd3d/vkd3d_private.h |  2 ++
 3 files changed, 21 insertions(+), 1 deletion(-)

diff --git a/libs/vkd3d/device.c b/libs/vkd3d/device.c
index 84053f0b..0012e4cb 100644
--- a/libs/vkd3d/device.c
+++ b/libs/vkd3d/device.c
@@ -84,6 +84,7 @@ static const struct vkd3d_optional_extension_info optional_device_extensions[] =
     VK_EXTENSION(KHR_MAINTENANCE_8, KHR_maintenance8),
     VK_EXTENSION(KHR_MAINTENANCE_9, KHR_maintenance9),
     VK_EXTENSION(KHR_MAINTENANCE_10, KHR_maintenance10),
+    VK_EXTENSION(KHR_MAINTENANCE_11, KHR_maintenance11),
     VK_EXTENSION(KHR_SHADER_MAXIMAL_RECONVERGENCE, KHR_shader_maximal_reconvergence),
     VK_EXTENSION(KHR_SHADER_QUAD_CONTROL, KHR_shader_quad_control),
     VK_EXTENSION(KHR_COMPUTE_SHADER_DERIVATIVES, KHR_compute_shader_derivatives),
@@ -2294,6 +2295,12 @@ static void vkd3d_physical_device_info_init(struct vkd3d_physical_device_info *i
         vkd3d_physical_device_info_init_maint10(info, device);
     }

+    if (vulkan_info->KHR_maintenance11)
+    {
+        info->maintenance_11_features.sType = VK_STRUCTURE_TYPE_PHYSICAL_DEVICE_MAINTENANCE_11_FEATURES_KHR;
+        vk_prepend_struct(&info->features2, &info->maintenance_11_features);
+    }
+
     if (vulkan_info->KHR_shader_maximal_reconvergence)
     {
         info->shader_maximal_reconvergence_features.sType = VK_STRUCTURE_TYPE_PHYSICAL_DEVICE_SHADER_MAXIMAL_RECONVERGENCE_FEATURES_KHR;
diff --git a/libs/vkd3d/resource.c b/libs/vkd3d/resource.c
index 92e87884..ad0213bb 100644
--- a/libs/vkd3d/resource.c
+++ b/libs/vkd3d/resource.c
@@ -873,6 +873,14 @@ static HRESULT vkd3d_get_image_create_info(struct d3d12_device *device,
             && desc->SampleDesc.Count == 1)
         image_info->flags |= VK_IMAGE_CREATE_CUBE_COMPATIBLE_BIT;

+    if (device->device_info.maintenance_11_features.maintenance11 && (
+            desc->Dimension == D3D12_RESOURCE_DIMENSION_TEXTURE1D ||
+            desc->Dimension == D3D12_RESOURCE_DIMENSION_TEXTURE2D))
+    {
+        /* Texture2D and Texture2DArray can be freely reinterpreted. */
+        image_info->flags |= VK_IMAGE_CREATE_ALIAS_SINGLE_LAYER_DESCRIPTOR_BIT_KHR;
+    }
+
     if (sparse_resource)
     {
         image_info->flags |= VK_IMAGE_CREATE_SPARSE_BINDING_BIT |
@@ -6401,9 +6409,12 @@ static void vkd3d_create_buffer_srv(vkd3d_cpu_descriptor_va_t desc_va,

 static void vkd3d_texture_view_desc_fixup(struct d3d12_device *device, struct vkd3d_texture_view_desc *desc)
 {
-    if (device->device_info.properties2.properties.vendorID == VKD3D_VENDOR_ID_NVIDIA)
+    if (!device->device_info.maintenance_11_features.maintenance11 &&
+        device->device_info.properties2.properties.vendorID == VKD3D_VENDOR_ID_NVIDIA)
     {
+        /* Fixed in maintenance11. */
         FIXME_ONCE("Remapping 2D to 2D_ARRAY. Needs Vulkan spec tightening to match D3D12 properly.\n");
+
         /* D3D allows some reinterpretation between Texture2D and Texture2DArray.
          * Texture2D in shader can read a resource with 1 array layer,
          * and Texture2DArray can read a Texture2D descriptor.
diff --git a/libs/vkd3d/vkd3d_private.h b/libs/vkd3d/vkd3d_private.h
index 3bd3d643..bfa45dcc 100644
--- a/libs/vkd3d/vkd3d_private.h
+++ b/libs/vkd3d/vkd3d_private.h
@@ -146,6 +146,7 @@ struct vkd3d_vulkan_info
     bool KHR_maintenance8;
     bool KHR_maintenance9;
     bool KHR_maintenance10;
+    bool KHR_maintenance11;
     bool KHR_shader_maximal_reconvergence;
     bool KHR_shader_quad_control;
     bool KHR_compute_shader_derivatives;
@@ -5132,6 +5133,7 @@ struct vkd3d_physical_device_info
     VkPhysicalDeviceMaintenance9FeaturesKHR maintenance_9_features;
     VkPhysicalDeviceMaintenance10FeaturesKHR maintenance_10_features;
     VkPhysicalDeviceMaintenance10PropertiesKHR maintenance_10_properties;
+    VkPhysicalDeviceMaintenance11FeaturesKHR maintenance_11_features;
     VkPhysicalDeviceLineRasterizationFeaturesEXT line_rasterization_features;
     VkPhysicalDeviceImageCompressionControlFeaturesEXT image_compression_control_features;
     VkPhysicalDeviceFaultFeaturesEXT fault_features;

