+        if (!dxgi_vk_swap_chain_poll_single_calibration(chain, chain->timing.time_domains[i],
+                chain->timing.time_domain_ids[i], chain->timing.calibration[i]))
+        {
+            FIXME("Failed to calibrate.\n");
+        }
+    }
+}
