-            signature->pipeline_type != VKD3D_PIPELINE_TYPE_COMPUTE &&
-            list->device->device_info.vulkan_1_2_properties.driverID == VK_DRIVER_ID_MESA_RADV &&
-            (list->vk_queue_flags & VK_QUEUE_GRAPHICS_BIT))
