     size_t query_pools_size;
     size_t query_pool_count;
@@ -5135,6 +5137,7 @@ struct vkd3d_queue_family_info
     uint32_t vk_family_index;
     uint32_t timestamp_bits;
     VkQueueFlags vk_queue_flags;
+    VkExtent3D transfer_granularity;
