+        alloc_info.commandPool = pool->fallback_pool;
+        if ((vr = VK_CALL(vkAllocateCommandBuffers(queue->device->vk_device, &alloc_info, pool->fallback_cmd))))
+            return hresult_from_vk_result(vr);
+    }
+
     return S_OK;
