+static uint8_t float_to_bf8(float v, bool saturate)
+{
+    union
+    {
+        float f32;
+        int32_t s32;
+    } u;
+    int i, s, e, m;
+
+    /* Matches RDNA4 HW behavior. Probably the point where we start rounding to 0x7f instead of 0x7e. */
+    if (v >= 61440.0f)
+        return saturate ? 0x7b : 0x7c;
+    else if (v <= -61440.0f)
+        return saturate ? 0xfb : 0xfc;
+
+    u.f32 = v;
+    i = u.s32;
+    s = (i >> 24) & 0x80;
+    e = ((i >> 23) & 0x000000ff) - (127 - 15);
+    m = i & 0x007fffff;
+
+    if (e <= 0)
+    {
+        int round_up;
+        int shamt;
+
+        if (e < -2)
+            return (uint8_t)s;
+
+        shamt = 1 - e;
+
+        round_up = m & ((1 << shamt) - 1);
+        m = (m | 0x800000) >> shamt;
+        round_up |= m & 0x2fffff;
+
+        if ((m & 0x100000) && round_up)
+            m += 0x200000;
+
+        m >>= 21;
+
+        return (uint8_t)(s | m);
+    }
+    else
+    {
+        int round_up;
+
+        round_up = m & 0x2fffff;
+
+        if ((m & 0x100000) && round_up)
+        {
+            m += 0x200000;
+
+            if (m & 0x800000)
+            {
+                m = 0;
+                e += 1;
+            }
+        }
+
+        return (uint16_t)(s | (e << 2) | (m >> 21));
+    }
+}
