+{
+    struct d3d12_device_factory *factory = impl_from_ID3D12DeviceFactory(iface);
+    ULONG refcount;
+    TRACE("iface %p\n", iface);
+    refcount = InterlockedDecrement(&factory->refcount);
+    if (refcount == 0)
+        vkd3d_free(factory);
+    return refcount;
