+static HRESULT STDMETHODCALLTYPE d3d12_device_factory_QueryInterface(ID3D12DeviceFactory *iface,
+        REFIID iid, void **object)
+{
+    TRACE("iface %p, riid %s, object %p.\n", iface, debugstr_guid(iid), object);
