+
+static ULONG STDMETHODCALLTYPE d3d12_sdk_configuration_AddRef(ID3D12SDKConfiguration1 *iface)
+{
+    struct d3d12_sdk_configuration *config = impl_from_ID3D12SDKConfiguration1(iface);
