+{
+    struct d3d12_sdk_configuration *config = impl_from_ID3D12SDKConfiguration1(iface);
+    ULONG refcount;
+    TRACE("iface %p\n", iface);
+    refcount = InterlockedDecrement(&config->refcount);
+    if (refcount == 0)
