commit 4bf043b47d42ff3e571eac5edf60fff6f1246fdf
Author: Hans-Kristian Arntzen <post@arntzen-software.no>
Date:   Wed Dec 3 11:56:17 2025 +0100

    vkd3d: Ignore loadOp compat requirement on known drivers.

    Having to split render passes for something like this is bad,
    and forcing the use of secondaries is also a no-go.

    I have proposed a maintenance feature to make this valid Vulkan
    everywhere.

    Signed-off-by: Hans-Kristian Arntzen <post@arntzen-software.no>
---
 libs/vkd3d/command.c       |  6 ++++--
 libs/vkd3d/device.c        | 17 +++++++++++++++++
 libs/vkd3d/vkd3d_private.h |  1 +
 3 files changed, 22 insertions(+), 2 deletions(-)

diff --git a/libs/vkd3d/command.c b/libs/vkd3d/command.c
index 2f78f62b..8b6492cf 100644
--- a/libs/vkd3d/command.c
+++ b/libs/vkd3d/command.c
@@ -7841,8 +7841,10 @@ static bool d3d12_command_list_render_pass_suspend_resume_avoids_fixup(
         return false;
     if (memcmp(suspend->layouts, resume->layouts, sizeof(resume->layouts)) != 0)
         return false;
-    if (memcmp(suspend->load_ops, resume->load_ops, sizeof(resume->load_ops)) != 0)
-        return false;
+
+    if (!first->device->workarounds.tiler_suspend_resume_relax_load_store_op)
+        if (memcmp(suspend->load_ops, resume->load_ops, sizeof(resume->load_ops)) != 0)
+            return false;

     return suspend->color_attachment_count == resume->color_attachment_count && suspend->view_mask == resume->view_mask;
 }
diff --git a/libs/vkd3d/device.c b/libs/vkd3d/device.c
index eacda512..47ee5cb3 100644
--- a/libs/vkd3d/device.c
+++ b/libs/vkd3d/device.c
@@ -3521,6 +3521,23 @@ static void d3d12_device_init_workarounds(struct d3d12_device *device)
             break;
     }

+    /* Having to split render passes when there is a mismatch in load-store ops is unfortunate.
+     * Be spec correct by default, and go a bit out of spec if we know the drivers are sensible. */
+    switch (device->device_info.vulkan_1_2_properties.driverID)
+    {
+        case VK_DRIVER_ID_MESA_TURNIP:
+        case VK_DRIVER_ID_MESA_RADV:
+        case VK_DRIVER_ID_MESA_NVK:
+        case VK_DRIVER_ID_INTEL_OPEN_SOURCE_MESA:
+        case VK_DRIVER_ID_NVIDIA_PROPRIETARY:
+            /* Currently only relevant on Turnip really, since that's where we enable suspend-resume by default. */
+            device->workarounds.tiler_suspend_resume_relax_load_store_op = true;
+            break;
+
+        default:
+            break;
+    }
+
     /* For testing purposes, allow us to exercise all code paths on all GPUs. */
     if (vkd3d_debug_control_get_behavior_flags() & VKD3D_DEBUG_CONTROL_BEHAVIOR_ENABLE_TILER_SYNC)
         device->workarounds.tiler_renderpass_barriers = true;
diff --git a/libs/vkd3d/vkd3d_private.h b/libs/vkd3d/vkd3d_private.h
index fa85e8dd..e6f93ba1 100644
--- a/libs/vkd3d/vkd3d_private.h
+++ b/libs/vkd3d/vkd3d_private.h
@@ -5475,6 +5475,7 @@ struct d3d12_device
         bool amdgpu_broken_null_tile_mapping;
         bool tiler_renderpass_barriers;
         bool tiler_suspend_resume;
+        bool tiler_suspend_resume_relax_load_store_op;
     } workarounds;

